mapper.select:
select sa.id, sa.product_id, sa.product_name, sa.current_stock, sa.alert_threshold, sa.alert_status, sa.alert_time, sa.handle_time, e.name as handle_user_name from stock_alert sa left join employee e on sa.handle_user = e.id
and sa.alert_status = #{alertStatus}
order by sa.alert_time desc
